4695     if (auto *TrueC = dyn_cast<Constant>(TrueVal))
4696       if (auto *FalseC = dyn_cast<Constant>(FalseVal))
4697         if (Constant *C = ConstantFoldSelectInstruction(CondC, TrueC, FalseC))
